impl Solution { pub fn maximum_rows(black_m: Vec<Vec<i32>>, black_s: i32) -> i32 { let (black_r, black_c) = (black_m.len(), black_m[0].len()); let black_v: Vec<i32> = black_m.iter().map(|row| row.iter().enumerate().fold(0, |acc, (j, &v)| acc | (v << j))).collect(); (0..(1 << black_c)).filter(|&mask| (mask as i32).count_ones() == black_s as u32).map(|mask| black_v.iter().filter(|&&row_mask| (row_mask & mask) == row_mask).count()).max().unwrap_or(0) as i32 } }